arguments.file_text:
@page "/catalog"
@namespace sv_ee9aac885f5b4f5e894016b4dbab0023.Components.Pages.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h1>Product Catalog</h1>

@if (_error is not null)
{
    <div class="catalog-error">
        <p>Something went wrong: @_error</p>
        <button @onclick="ReloadAsync">Try Again</button>
    </div>
}
else
{
    <div class="catalog-layout">
        <CatalogSidebar Categories="_categories"
                        Filter="_filter"
                        OnFilterApplied="HandleFilterApplied"
                        OnFilterCleared="HandleFilterCleared" />

        <main class="catalog-main">
            @if (_loading)
            {
                <div class="catalog-loading">
                    <p>Loading products…</p>
                </div>
            }
            else if (_result is not null)
            {
                <CatalogToolbar SortBy="@_sortBy"
                                TotalCount="_result.TotalCount"
                                CurrentPage="_result.Page"
                                PageSize="_result.PageSize"
                                OnSortChanged="HandleSortChanged" />

                <ProductGrid Products="_result.Items"
                             OnProductSelected="HandleProductSelected"
                             OnAddToCart="HandleAddToCart" />

                <CatalogPagination CurrentPage="_result.Page"
                                   TotalPages="TotalPages"
                                   OnPageChanged="HandlePageChanged" />
            }
        </main>
    </div>
}

@code {
    private List<string> _categories = [];
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private const int PageSize = 12;

    private PagedResult<Product>? _result;
    private bool _loading = true;
    private string? _error;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private int TotalPages =>
        _result is null ? 0 : (int)Math.Ceiling((double)_result.TotalCount / _result.PageSize);

    protected override async Task OnInitializedAsync()
    {
        await ReloadAsync();
    }

    private async Task ReloadAsync()
    {
        try
        {
            _error = null;
            _loading = true;

            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            _categories = await categoriesTask;
            _result = await searchTask;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task SearchAsync()
    {
        try
        {
            _error = null;
            _loading = true;
            _result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleFilterCleared()
    {
        _filter = new(null, null, null, false);
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await SearchAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Cart integration point
        return Task.CompletedTask;
    }
}

.catalog-layout {
    display: flex;
    gap: 1.5rem;
}

/* Sidebar */
.catalog-sidebar {
    flex: 0 0 25%;
    min-width: 220px;
    border-right: 1px solid #e0e0e0;
    padding-right: 1.5rem;
}

.catalog-sidebar h2 {
    margin-top: 0;
    font-size: 1.25rem;
}

.catalog-sidebar h3 {
    font-size: 1rem;
    margin: 1rem 0 0.5rem;
}

.filter-section {
    margin-bottom: 1rem;
}

.filter-checkbox {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    margin-bottom: 0.35rem;
    cursor: pointer;
}

.price-inputs {
    display: flex;
    gap: 0.75rem;
}

.price-inputs label {
    display: flex;
    flex-direction: column;
    font-size: 0.85rem;
}

.price-inputs input {
    width: 90px;
    padding: 0.3rem 0.4rem;
    margin-top: 0.2rem;
}

.filter-actions {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    margin-top: 1rem;
}

.btn-apply,
.btn-clear {
    padding: 0.5rem 1rem;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.9rem;
}

.btn-apply {
    background: #0d6efd;
    color: #fff;
}

.btn-apply:hover {
    background: #0b5ed7;
}

.btn-clear {
    background: #e9ecef;
    color: #333;
}

.btn-clear:hover {
    background: #dee2e6;
}

/* Main content */
.catalog-main {
    flex: 1;
    min-width: 0;
}

/* Toolbar */
.catalog-toolbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 1rem;
    flex-wrap: wrap;
    gap: 0.5rem;
}

.toolbar-sort {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.toolbar-sort select {
    padding: 0.35rem 0.5rem;
    border-radius: 4px;
    border: 1px solid #ccc;
}

.toolbar-info {
    color: #666;
    font-size: 0.9rem;
}

/* Product grid */
.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
    gap: 1.25rem;
}

.product-card {
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    overflow: hidden;
    cursor: pointer;
    transition: box-shadow 0.2s;
    display: flex;
    flex-direction: column;
}

.product-card:hover {
    box-shadow: 0 2px 12px rgba(0, 0, 0, 0.12);
}

.product-image {
    background: #f0f0f0;
    height: 160px;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #999;
    font-size: 0.85rem;
    text-align: center;
    padding: 0.5rem;
}

.product-info {
    padding: 0.75rem;
    display: flex;
    flex-direction: column;
    gap: 0.35rem;
    flex: 1;
}

.product-name {
    margin: 0;
    font-size: 1rem;
}

.product-price {
    margin: 0;
    font-weight: 600;
    color: #2e7d32;
}

.product-rating {
    color: #f5a623;
    font-size: 1.1rem;
}

.badge-out-of-stock {
    display: inline-block;
    background: #dc3545;
    color: #fff;
    font-size: 0.75rem;
    padding: 0.15rem 0.5rem;
    border-radius: 4px;
    align-self: flex-start;
}

.btn-add-to-cart {
    margin-top: auto;
    padding: 0.45rem 0.75rem;
    background: #0d6efd;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.85rem;
}

.btn-add-to-cart:hover:not(:disabled) {
    background: #0b5ed7;
}

.btn-add-to-cart:disabled {
    background: #adb5bd;
    cursor: not-allowed;
}

/* Pagination */
.catalog-pagination {
    display: flex;
    justify-content: center;
    gap: 0.35rem;
    margin-top: 1.5rem;
    flex-wrap: wrap;
}

.btn-page {
    padding: 0.4rem 0.75rem;
    border: 1px solid #dee2e6;
    background: #fff;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.9rem;
}

.btn-page:hover:not(:disabled):not(.active) {
    background: #e9ecef;
}

.btn-page.active {
    background: #0d6efd;
    color: #fff;
    border-color: #0d6efd;
}

.btn-page:disabled {
    color: #adb5bd;
    cursor: not-allowed;
}

/* States */
.catalog-loading,
.empty-results,
.catalog-error {
    text-align: center;
    padding: 2rem;
    color: #666;
}

.catalog-error {
    color: #dc3545;
}

.catalog-error button {
    margin-top: 0.5rem;
    padding: 0.4rem 1rem;
    background: #0d6efd;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
}

